      href: Router.RelativePathString | Router.ExternalPathString | `/add-lesson${`?${string}` | `#${string}` | ''}` | `/awaiting-approval${`?${string}` | `#${string}` | ''}` | `/edit-lesson${`?${string}` | `#${string}` | ''}` | `/login${`?${string}` | `#${string}` | ''}` | `/modal${`?${string}` | `#${string}` | ''}` | `/_sitemap${`?${string}` | `#${string}` | ''}` | `${'/(tabs)'}/admin${`?${string}` | `#${string}` | ''}` | `/admin${`?${string}` | `#${string}` | ''}` | `${'/(tabs)'}${`?${string}` | `#${string}` | ''}` | `/${`?${string}` | `#${string}` | ''}` | `${'/(tabs)'}/school-history${`?${string}` | `#${string}` | ''}` | `/school-history${`?${string}` | `#${string}` | ''}` | `${'/(tabs)'}/schools${`?${string}` | `#${string}` | ''}` | `/schools${`?${string}` | `#${string}` | ''}` | `${'/(tabs)'}/settings${`?${string}` | `#${string}` | ''}` | `/settings${`?${string}` | `#${string}` | ''}` | { pathname: Router.RelativePathString, params?: Router.UnknownInputParams } | { pathname: Router.ExternalPathString, params?: Router.UnknownInputParams } | { pathname: `/add-lesson`; params?: Router.UnknownInputParams; } | { pathname: `/awaiting-approval`; params?: Router.UnknownInputParams; } | { pathname: `/edit-lesson`; params?: Router.UnknownInputParams; } | { pathname: `/login`; params?: Router.UnknownInputParams; } | { pathname: `/modal`; params?: Router.UnknownInputParams; } | { pathname: `/_sitemap`; params?: Router.UnknownInputParams; } | { pathname: `${'/(tabs)'}/admin` | `/admin`; params?: Router.UnknownInputParams; } | { pathname: `${'/(tabs)'}` | `/`; params?: Router.UnknownInputParams; } | { pathname: `${'/(tabs)'}/school-history` | `/school-history`; params?: Router.UnknownInputParams; } | { pathname: `${'/(tabs)'}/schools` | `/schools`; params?: Router.UnknownInputParams; } | { pathname: `${'/(tabs)'}/settings` | `/settings`; params?: Router.UnknownInputParams; } | `/admin/teacher/${Router.SingleRoutePart<T>}${`?${string}` | `#${string}` | ''}` | `/admin/teacher/${Router.SingleRoutePart<T>}/school/${Router.SingleRoutePart<T>}${`?${string}` | `#${string}` | ''}` | `/school/${Router.SingleRoutePart<T>}${`?${string}` | `#${string}` | ''}` | { pathname: `/admin/teacher/[uid]`, params: Router.UnknownInputParams & { uid: string | number; } } | { pathname: `/admin/teacher/[uid]/school/[schoolName]`, params: Router.UnknownInputParams & { uid: string | number;schoolName: string | number; } } | { pathname: `/school/[id]`, params: Router.UnknownInputParams & { id: string | number; } };
    }
